/**
 * Generated by `createservice miniapp.GetOIDCClientService '--type=queries'`
 */

const { faker } = require('@faker-js/faker')
const dayjs = require('dayjs')

const { generateGqlQueries } = require('@open-condo/codegen/generate.gql')
const { generateGQLTestUtils } = require('@open-condo/codegen/generate.test.utils')
const { makeClient } = require('@open-condo/keystone/test.utils')
const { expectToThrowAccessDeniedErrorToResult, expectToThrowAuthenticationErrorToResult } = require('@open-condo/keystone/test.utils')

const { DEV_ENVIRONMENT } = require('@dev-portal-api/domains/miniapp/constants/publishing')
const { generatePayload } = require('@dev-portal-api/domains/miniapp/utils/serverSchema/oidcClient')
const {
    getOIDCClientByTestClient,
    createTestB2CApp,
    updateTestB2CApp,
    createTestB2BApp,
    createOIDCClientByTestClient,
    publishB2CAppByTestClient,
    B2CApp,
} = require('@dev-portal-api/domains/miniapp/utils/testSchema')
const {
    makeLoggedInAdminClient,
    makeLoggedInSupportClient,
    makeRegisteredAndLoggedInUser,
    makeLoggedInCondoAdminClient,
} = require('@dev-portal-api/domains/user/utils/testSchema')

const CondoB2CApp = generateGQLTestUtils(generateGqlQueries('B2CApp', '{ id importId oidcClient { id } }'))
const CondoOIDCClient = generateGQLTestUtils(generateGqlQueries('OidcClient', '{ id clientId payload isEnabled deletedAt importId importRemoteSystem }'))
 
describe('GetOIDCClientService', () => {
    let admin
    let support
    let b2cUser
    let b2cApp
    let b2bUser
    let b2bApp
    let anonymous
    let b2cOIDCClient
    let b2bOIDCClient
    beforeAll(async () => {
        admin = await makeLoggedInAdminClient()
        support = await makeLoggedInSupportClient()
        b2cUser = await makeRegisteredAndLoggedInUser()
        b2bUser = await makeRegisteredAndLoggedInUser()
        anonymous = await makeClient();

        [b2cApp] = await createTestB2CApp(b2cUser);
        [b2cOIDCClient] = await createOIDCClientByTestClient(b2cUser, b2cApp);

        [b2bApp] = await createTestB2BApp(b2bUser);
        [b2bOIDCClient] = await createOIDCClientByTestClient(b2bUser, b2bApp)
    })
    describe('Access tests', () => {
        test('Admin can get OIDC client of any app', async () => {
            const [readClient] = await getOIDCClientByTestClient(admin, b2cApp)
            expect(readClient).toHaveProperty('id', b2cOIDCClient.id)
            expect(readClient).toHaveProperty('clientId', b2cOIDCClient.clientId)
            expect(readClient).toHaveProperty('redirectUri', b2cOIDCClient.redirectUri)
        })
        test('Support can get OIDC client of any app', async () => {
            const [readClient] = await getOIDCClientByTestClient(support, b2bApp)
            expect(readClient).toHaveProperty('id', b2bOIDCClient.id)
            expect(readClient).toHaveProperty('clientId', b2bOIDCClient.clientId)
            expect(readClient).toHaveProperty('redirectUri', b2bOIDCClient.redirectUri)
        })
        describe('User', () => {
            describe('Can get OIDC client of app he created',  () => {
                test('For B2BApp', async () => {
                    const [readClient] = await getOIDCClientByTestClient(b2bUser, b2bApp)
                    expect(readClient).toHaveProperty('id', b2bOIDCClient.id)
                    expect(readClient).toHaveProperty('clientId', b2bOIDCClient.clientId)
                    expect(readClient).toHaveProperty('redirectUri', b2bOIDCClient.redirectUri)
                })
                test('For B2CApp', async () => {
                    const [readClient] = await getOIDCClientByTestClient(b2cUser, b2cApp)
                    expect(readClient).toHaveProperty('id', b2cOIDCClient.id)
                    expect(readClient).toHaveProperty('clientId', b2cOIDCClient.clientId)
                    expect(readClient).toHaveProperty('redirectUri', b2cOIDCClient.redirectUri)
                })
            })
            test('Cannot for other apps', async () => {
                await expectToThrowAccessDeniedErrorToResult(async () => {
                    await getOIDCClientByTestClient(b2bUser, b2cApp)
                })
                await expectToThrowAccessDeniedErrorToResult(async () => {
                    await getOIDCClientByTestClient(b2cUser, b2bApp)
                })
            })
        })
        test('Anonymous cannot get any OIDC client', async () => {
            await expectToThrowAuthenticationErrorToResult(async () => {
                await getOIDCClientByTestClient(anonymous, b2cApp)
            })
        })
    })
    describe('Logic tests', () => {
        test('Must not contain extra fields such as clientSecret', async () => {
            const [readClient] = await getOIDCClientByTestClient(b2cUser, b2cApp)
            expect(readClient).toEqual({
                id: b2cOIDCClient.id,
                clientId: b2cOIDCClient.clientId,
                redirectUri: b2cOIDCClient.redirectUri,
                isEnabled: expect.any(Boolean),
            })
        })
        describe('Resolution order', () => {
            /**
             * Three candidates are set up using direct condo calls to decouple from dev-portal business logic:
             *   - Candidate 1 (condoApp.oidcClient): a condo OIDCClient linked on the condoApp side
             *   - Candidate 2 (oidcClientId field):  a condo OIDCClient referenced by dev-portal app.developmentOidcClientId
             *   - Candidate 3 (legacy importId):     a condo OIDCClient with importId=app.id (created via CreateOIDCClientService)
             *
             * beforeEach recreates all 3 candidates fresh so each test is fully independent.
             */
            let condoAdmin
            let user
            let app
            let condoApp
            let clientLinkedToCondoApp
            let clientFromOidcClientId
            let clientFromImportId

            beforeAll(async () => {
                condoAdmin = await makeLoggedInCondoAdminClient()
                user = await makeRegisteredAndLoggedInUser();

                [app] = await createTestB2CApp(user)

                // Publish once to create the condoApp — reused across all tests
                await publishB2CAppByTestClient(user, app, { info: true }, DEV_ENVIRONMENT)
                const refreshedApp = await B2CApp.getOne(user, { id: app.id })
                condoApp = await CondoB2CApp.getOne(condoAdmin, { id: refreshedApp.developmentExportId });

                // Candidate 3: legacy importId client — created once since clientId=app.id is unique per app
                [clientFromImportId] = await createOIDCClientByTestClient(user, app)
            })

            beforeEach(async () => {
                const sender = { dv: 1, fingerprint: faker.random.alphaNumeric(8) }

                // Candidate 2: a separate condo OIDCClient referenced via dev-portal oidcClientId field
                const oidcClientIdCandidateId = faker.datatype.uuid()
                clientFromOidcClientId = await CondoOIDCClient.create(condoAdmin, {
                    dv: 1,
                    sender,
                    clientId: oidcClientIdCandidateId,
                    name: `[test] oidcClientId candidate for ${app.id}`,
                    payload: generatePayload(oidcClientIdCandidateId, faker.internet.url() + '/'),
                    isEnabled: true,
                })
                await updateTestB2CApp(admin, app.id, { developmentOidcClientId: clientFromOidcClientId.id })

                // Candidate 1: a separate condo OIDCClient linked directly on condoApp.oidcClient
                const condoAppCandidateId = faker.datatype.uuid()
                clientLinkedToCondoApp = await CondoOIDCClient.create(condoAdmin, {
                    dv: 1,
                    sender,
                    clientId: condoAppCandidateId,
                    name: `[test] condoApp.oidcClient candidate for ${app.id}`,
                    payload: generatePayload(condoAppCandidateId, faker.internet.url() + '/'),
                    isEnabled: true,
                })
                await CondoB2CApp.update(condoAdmin, condoApp.id, {
                    dv: 1,
                    sender,
                    oidcClient: { connect: { id: clientLinkedToCondoApp.id } },
                })
            })

            test('Returns condoApp.oidcClient when all 3 candidates exist', async () => {
                const [result] = await getOIDCClientByTestClient(admin, app)
                expect(result).toHaveProperty('id', clientLinkedToCondoApp.id)
            })

            test('Falls back to oidcClientId when condoApp.oidcClient is deleted', async () => {
                await CondoOIDCClient.update(condoAdmin, clientLinkedToCondoApp.id, {
                    dv: 1,
                    sender: { dv: 1, fingerprint: faker.random.alphaNumeric(8) },
                    deletedAt: dayjs().toISOString(),
                })

                const [result] = await getOIDCClientByTestClient(admin, app)
                expect(result).toHaveProperty('id', clientFromOidcClientId.id)
            })

            test('Falls back to importId client when condoApp.oidcClient and oidcClientId are deleted', async () => {
                const sender = { dv: 1, fingerprint: faker.random.alphaNumeric(8) }
                await CondoOIDCClient.update(condoAdmin, clientLinkedToCondoApp.id, {
                    dv: 1,
                    sender,
                    deletedAt: dayjs().toISOString(),
                })
                await CondoOIDCClient.update(condoAdmin, clientFromOidcClientId.id, {
                    dv: 1,
                    sender,
                    deletedAt: dayjs().toISOString(),
                })

                const [result] = await getOIDCClientByTestClient(admin, app)
                expect(result).toHaveProperty('id', clientFromImportId.id)
            })

            test('Returns null when all candidates are deleted', async () => {
                const sender = { dv: 1, fingerprint: faker.random.alphaNumeric(8) }
                await CondoOIDCClient.update(condoAdmin, clientLinkedToCondoApp.id, {
                    dv: 1,
                    sender,
                    deletedAt: dayjs().toISOString(),
                })
                await CondoOIDCClient.update(condoAdmin, clientFromOidcClientId.id, {
                    dv: 1,
                    sender,
                    deletedAt: dayjs().toISOString(),
                })
                await CondoOIDCClient.update(condoAdmin, clientFromImportId.id, {
                    dv: 1,
                    sender,
                    deletedAt: dayjs().toISOString(),
                })

                const [result] = await getOIDCClientByTestClient(admin, app)
                expect(result).toBeNull()
            })
        })
    })
})